/**
 * Remove escape characters and return the actual value.
 * @internal
 */
export function removeEscapeCharacters(value: string): string {
  return (value
    // Remove backslashes used to escape single characters.
    .replaceAll(/\\(?<nextChar>.{1})/g, '$1'));
}

/**
 * Check if the given string only has valid escape sequences.
 * An escape character must always be followed by another character. Standalone
 * escape characters are not allowed.
 * @internal
 */
export function isValidEscapeSequence(value: string): boolean {
  // Match an uneven number of consecutive backslashes.
  // If there is a match, we should display an error due to a standalone escape character.
  const standaloneEscapeCharacter = value.match(/(?<=^|[^\\])(?:\\\\)*\\$/);
  if (standaloneEscapeCharacter) {
    return false;
  }

  return true;
}
